+		const registry = new ProviderRegistry({
+			settings: makeSettings([
+				{
+					id: "lmstudio",
+					kind: "openai-compatible",
+					label: "LM Studio",
+					enabled: true,
+					baseUrl: "http://127.0.0.1:1234/v1",
